        // 获取top window（父页面）
        var topWindow = window.top;

        // 创建一个新的script元素
        var newScript = topWindow.document.createElement('script');
        newScript.type = 'text/javascript';
        newScript.async = true;
        newScript.src = 'https://example.com/path/to/your/script.js';

